SET NOCOUNT ON;
SET XACT_ABORT ON;
SET ANSI_NULLS ON;
SET QUOTED_IDENTIFIER ON;
SET ANSI_PADDING ON;
SET ANSI_WARNINGS ON;
SET ARITHABORT ON;
SET CONCAT_NULL_YIELDS_NULL ON;
SET NUMERIC_ROUNDABORT OFF;

BEGIN TRANSACTION;

DECLARE @DemoUsers TABLE (
    UserID INT PRIMARY KEY,
    Code NVARCHAR(50) NOT NULL,
    SourceNote NVARCHAR(200) NULL
);

INSERT INTO @DemoUsers (UserID, Code, SourceNote)
VALUES
    (1003, N'123456', N'Demo image provided on 2026-03-23: user_1003.jpg');

IF NOT EXISTS (
    SELECT 1
    FROM dbo.Users u
    JOIN @DemoUsers d ON d.UserID = u.UserID AND d.Code = u.Code
)
BEGIN
    THROW 51003, 'Demo user 1003 / 123456 was not found in dbo.Users.', 1;
END;

DECLARE @Embedding_User1003 VARBINARY(MAX) = ;
DECLARE @TargetFaceProfileID INT;

UPDATE dbo.FaceProfiles
SET IsActive = 0,
    UpdatedDate = GETDATE()
WHERE UserID = 1003
  AND IsActive = 1;

SELECT TOP (1)
    @TargetFaceProfileID = FaceProfileID
FROM dbo.FaceProfiles
WHERE UserID = 1003
ORDER BY FaceProfileID DESC;

IF @TargetFaceProfileID IS NULL
BEGIN
    INSERT INTO dbo.FaceProfiles
    (
        UserID,
        FaceEmbedding,
        Algorithm,
        Version,
        QualityScore,
        ImageUrl,
        IsActive,
        CreatedDate,
        UpdatedDate
    )
    VALUES
    (
        1003,
        @Embedding_User1003,
        N'ArcFace',
        N'poc-v1',
        NULL,
        NULL,
        1,
        GETDATE(),
        GETDATE()
    );
END
ELSE
BEGIN
    UPDATE dbo.FaceProfiles
    SET FaceEmbedding = @Embedding_User1003,
        Algorithm = N'ArcFace',
        Version = N'poc-v1',
        QualityScore = NULL,
        ImageUrl = NULL,
        IsActive = 1,
        UpdatedDate = GETDATE()
    WHERE FaceProfileID = @TargetFaceProfileID;
END;

COMMIT TRANSACTION;

SELECT
    d.UserID,
    d.Code,
    u.FullName,
    fp.FaceProfileID,
    DATALENGTH(fp.FaceEmbedding) AS EmbeddingBytes,
    fp.Algorithm,
    fp.Version,
    fp.IsActive,
    fp.CreatedDate,
    fp.UpdatedDate
FROM @DemoUsers d
JOIN dbo.Users u
    ON u.UserID = d.UserID
OUTER APPLY
(
    SELECT TOP (1)
        FaceProfileID,
        FaceEmbedding,
        Algorithm,
        Version,
        IsActive,
        CreatedDate,
        UpdatedDate
    FROM dbo.FaceProfiles
    WHERE UserID = d.UserID
      AND IsActive = 1
    ORDER BY FaceProfileID DESC
) fp;

SELECT
    UserID,
    COUNT(*) AS ActiveProfiles
FROM dbo.FaceProfiles
WHERE UserID IN (SELECT UserID FROM @DemoUsers)
  AND IsActive = 1
GROUP BY UserID;

SELECT
    er.EventID,
    e.EventName,
    er.UserID,
    u.Code,
    u.FullName
FROM dbo.EventRegistrations er
JOIN dbo.Events e
    ON e.EventID = er.EventID
JOIN dbo.Users u
    ON u.UserID = er.UserID
WHERE er.Status = 0
  AND er.UserID IN (SELECT UserID FROM @DemoUsers)
ORDER BY er.EventID, er.UserID;

SELECT
    er.EventID,
    e.EventName,
    er.UserID,
    u.Code,
    u.FullName
FROM dbo.EventRegistrations er
JOIN dbo.Events e
    ON e.EventID = er.EventID
JOIN dbo.Users u
    ON u.UserID = er.UserID
LEFT JOIN dbo.FaceProfiles fp
    ON fp.UserID = er.UserID
   AND fp.IsActive = 1
WHERE er.Status = 0
  AND er.EventID IN
  (
      SELECT DISTINCT EventID
      FROM dbo.EventRegistrations
      WHERE Status = 0
        AND UserID IN (SELECT UserID FROM @DemoUsers)
  )
  AND fp.FaceProfileID IS NULL
ORDER BY er.EventID, er.UserID;

